### 4. Cache Behavior Tests

```rust
#[cfg(test)]
mod cache_tests {
    #[tokio::test]
    async fn test_discovery_cache_invalidates_on_install() {
        let host = TestHost::new().await;

        // First discover
        let r1 = host.discover(None).await.unwrap();
        assert_eq!(r1.connectors.len(), 0);

        // Install connector
        host.install_connector("new-connector").await;

        // Cache should be invalidated
        let r2 = host.discover(None).await.unwrap();
        assert_eq!(r2.connectors.len(), 1);
    }

    #[tokio::test]
    async fn test_discovery_cache_invalidates_on_uninstall() {
        let host = TestHost::new().await;
        host.install_connector("test-connector").await;

        let r1 = host.discover(None).await.unwrap();
        assert_eq!(r1.connectors.len(), 1);

        host.uninstall_connector("test-connector").await;

        let r2 = host.discover(None).await.unwrap();
        assert_eq!(r2.connectors.len(), 0);
    }

    #[tokio::test]
    async fn test_discovery_cache_invalidates_on_health_change() {
        let host = TestHost::new().await;
        host.install_connector("test-connector").await;

        let r1 = host.discover(None).await.unwrap();
        assert_eq!(r1.connectors[0].health.status, HealthStatus::Healthy);

        host.mark_unhealthy("test-connector").await;

        let r2 = host.discover(None).await.unwrap();
        assert_eq!(r2.connectors[0].health.status, HealthStatus::Unhealthy);
    }
}
