        host.install_connector("normal-connector").await;
        host.install_crashing_connector("crashing-connector").await;

        // Should still return healthy connectors
        let response = host.discover(None).await.unwrap();

        assert!(response.connectors.iter().any(|c| c.id.as_str() == "normal-connector"));
    }
}
```

